import{St as e,ct as t,lt as n,q as r}from"./chunks/framework.CmioJCXl.js";var i=JSON.parse(`{"title":"全国大学生数学竞赛","description":"全国大学生数学竞赛（CMC）简介及简单的参赛指导","frontmatter":{"lang":"zh-CN","title":"全国大学生数学竞赛","description":"全国大学生数学竞赛（CMC）简介及简单的参赛指导"},"headers":[],"relativePath":"en/learn/extra/contest/cmc.md","filePath":"en/learn/extra/contest/cmc.md","lastUpdated":1784220723000}`),a={name:`en/learn/extra/contest/cmc.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="全国大学生数学竞赛" tabindex="-1">全国大学生数学竞赛 <a class="header-anchor" href="#全国大学生数学竞赛" aria-label="Permalink to “全国大学生数学竞赛”">​</a></h1><p><strong>主办方：中国数学会</strong></p><h3 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h3><p>全国大学生数学竞赛（The Chinese Mathematics Competitions for College Students，简称CMC）是由中国数学会主办、面向本科学生的全国性高水平学科竞赛。总体分为三组:<strong>数学组</strong>，<strong>非数学组A组</strong>，<strong>非数学组B组</strong></p><p><strong>赛区是初赛,全省前15名有机会能进入决赛，参加国赛</strong></p><h3 id="考核内容" tabindex="-1">考核内容 <a class="header-anchor" href="#考核内容" aria-label="Permalink to “考核内容”">​</a></h3><ul><li><strong>数学组</strong>:高数线代解析几何</li><li><strong>非数学A组</strong>:高数</li><li><strong>非数学B组</strong>:高数简单版</li></ul><h3 id="好处" tabindex="-1">好处 <a class="header-anchor" href="#好处" aria-label="Permalink to “好处”">​</a></h3><ul><li><strong>综测智育+分</strong>:省一5分，省二3分，省三1分(<strong>PS:智育3倍加分</strong>)</li><li><strong>保研加分:</strong>国一可以保研</li></ul><hr><h3 id="报名时间" tabindex="-1">报名时间 <a class="header-anchor" href="#报名时间" aria-label="Permalink to “报名时间”">​</a></h3><p>9月中旬到9月底，关注<a href="https://www2.scut.edu.cn/math/" target="_blank" rel="noreferrer">华南理工大学数学学院</a>通知</p><h4 id="类别一-校赛优秀" tabindex="-1">类别一：校赛优秀 <a class="header-anchor" href="#类别一-校赛优秀" aria-label="Permalink to “类别一：校赛优秀”">​</a></h4><p>9月份开学参加华工举办的大学生数学竞赛校赛，一等奖可以报销报名费</p><h4 id="类别二-自主报名" tabindex="-1">类别二：自主报名 <a class="header-anchor" href="#类别二-自主报名" aria-label="Permalink to “类别二：自主报名”">​</a></h4><p>报名费100元</p><h3 id="参赛时间" tabindex="-1">参赛时间 <a class="header-anchor" href="#参赛时间" aria-label="Permalink to “参赛时间”">​</a></h3><p>每年11月份初</p><hr><h3 id="备考方针-数学组" tabindex="-1">备考方针（数学组） <a class="header-anchor" href="#备考方针-数学组" aria-label="Permalink to “备考方针（数学组）”">​</a></h3><p>敬请期待</p><hr><h3 id="备考方针-非数学组" tabindex="-1">备考方针（非数学组） <a class="header-anchor" href="#备考方针-非数学组" aria-label="Permalink to “备考方针（非数学组）”">​</a></h3><h4 id="速成版-适合大一新生快速拿奖" tabindex="-1">速成版(适合大一新生快速拿奖) <a class="header-anchor" href="#速成版-适合大一新生快速拿奖" aria-label="Permalink to “速成版(适合大一新生快速拿奖)”">​</a></h4><p><strong>利益相关</strong>: 2024级 Oplisty，广东赛区省一</p><p>因为大部分知识点都在考察高数上所以一定要<strong>踏踏实实学完高数上</strong>,建议为期一个月,就是<strong>开学一个月速通高数上</strong>,本人用的是<strong>高等微积分教程(清华大学出版社)</strong>,每章<strong>看书做课后题，章后练习题不做</strong>,为期一个月，然后在<strong>10月份速通高数下</strong>,同样是<strong>高等微积分教程</strong>，同理，考前一周登录<a href="https://www.cmathc.org.cn/shiti/" target="_blank" rel="noreferrer">全国大学生数学竞赛官网</a>进行刷题,<strong>不会的题背住相关解法</strong></p><p>什么？你太摆了？</p><p>没关系！</p><p>因为这个本质上是考试而且难度大概率和中上985期末考试差不多，既然他们能速通你为何不可？</p><p><strong>Bilibili去搜索速通网课然后看完直接开始做题即可</strong>，重点如下</p><ul><li>曲线曲面二重三重积分</li><li>级数(必考最后一题,还有可能填空)</li><li>偏导计算和链式法则</li><li>求极限的常见方法</li><li>微分方程</li></ul><p><strong>优先搞定上面的即可</strong>,最少省三好吧,好点就省二省一了</p><h4 id="复习资料" tabindex="-1">复习资料 <a class="header-anchor" href="#复习资料" aria-label="Permalink to “复习资料”">​</a></h4><p>一本就够了，你大概率没时间做</p><ul><li>全国大学生数学竞赛解析教程上下(红皮书:科学出版社)</li></ul>`,35)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};